const e={"IR-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated an Incident Response Policy consistent with DoDI 8530.01, CJCSM 6510.01B, and NIST SP 800-61. Requires 72-hour reporting to DoD per DFARS 252.204-7012. Reviewed annually. The [ISSO] coordinates incident response for [SYSTEM].",tools:[]},"IR-2":{title:"Incident Response Training",body:"Personnel with IR responsibilities receive training within 10 days of assignment and annually thereafter covering: incident identification, classification, reporting, containment, evidence preservation, and communication protocols. [TOOL:crowdstrike] platform training is provided to security personnel. IR training is incorporated into annual tabletop exercises. Completion documented and reported to [ISSM].",tools:["crowdstrike"]},"IR-2(1)":{title:"IR Training | Simulated Events",body:"[ORG] incorporates simulated events into incident response training. Annual tabletop exercises include realistic scenarios: ransomware, data exfiltration, insider threat, and supply chain compromise. [TOOL:crowdstrike] and [TOOL:splunk] are used as training tools during exercises. After-action reports identify training gaps and drive improvements.",tools:["crowdstrike","splunk"]},"IR-2(2)":{title:"IR Training | Automated Training Environments",body:"[ORG] provides automated training environments for incident response. Security personnel train on [TOOL:crowdstrike] Falcon platform using training tenants and tabletop scenarios. [TOOL:splunk] training environments provide hands-on log analysis practice. Training environment exercises are conducted quarterly for security personnel.",tools:["crowdstrike","splunk"]},"IR-3":{title:"Incident Response Testing",body:"[ORG] tests [SYSTEM] IR capability annually via tabletop or functional exercise. Testing validates: detection ([TOOL:crowdstrike], [TOOL:splunk]), notification procedures, containment, recovery, and reporting timelines. Test results documented. Deficiencies tracked in POAM in [TOOL:emass]. After-action reports provided to [ISSM] and [AO].",tools:["crowdstrike","splunk","emass"]},"IR-3(2)":{title:"IR Testing | Coordination with Related Plans",body:"[ORG] coordinates incident response testing with plans including: Contingency Plan, Insider Threat Plan, and Crisis Communications Plan. Joint exercises test plan compatibility and identify gaps. The [ISSM] coordinates cross-plan exercise scheduling. Combined exercise results improve plan alignment.",tools:[]},"IR-4":{title:"Incident Handling",body:"[ORG] implements an IR capability covering preparation, detection, analysis, containment, eradication, and recovery. [TOOL:crowdstrike] provides automated detection and host isolation. [TOOL:splunk] provides SIEM-based detection and correlation. [TOOL:hbss] provides host-based detection. [ISSO] coordinates response. Incidents reported to [ISSM] within 1 hour and US-CERT/CISA within 72 hours per DFARS 252.204-7012.",tools:["crowdstrike","splunk","hbss"]},"IR-4(1)":{title:"Incident Handling | Automated Incident Handling Processes",body:"[SYSTEM] employs automated mechanisms to support incident handling. [TOOL:crowdstrike] provides automated threat detection, alerting, and host isolation. [TOOL:splunk] automates log correlation and alert generation. Automated responses include: immediate alerting to [ISSO], ticket creation in [ORG]'s ticketing system, and preservation of forensic artifacts. Automated responses are reviewed and approved by the [ISSM] annually.",tools:["crowdstrike","splunk"]},"IR-4(6)":{title:"Incident Handling | Insider Threats",body:"[ORG] implements incident handling capability for insider threats. [TOOL:crowdstrike] behavioral analytics monitor for insider threat indicators including unusual data access, large file transfers, and after-hours activity. [TOOL:splunk] user behavior analytics identify anomalous user patterns. Insider threat incidents are escalated to the [ISSM], Personnel Security Officer, and applicable counterintelligence resources. Insider threat response procedures are documented in the IR plan.",tools:["crowdstrike","splunk"]},"IR-4(8)":{title:"Incident Handling | Correlation with External Organizations",body:"[ORG] coordinates incident handling activities with external organizations for cross-organizational incidents. [ORG] maintains relationships with: US-CERT, DCSA ISOC, and applicable CSSP. Incident information is shared per applicable information sharing agreements. [TOOL:crowdstrike] threat intelligence is shared with authorized partners. Cross-organizational incident coordination procedures are documented in the IR plan.",tools:["crowdstrike"]},"IR-5":{title:"Incident Monitoring",body:"Incidents tracked in [ORG]'s incident tracking system from detection through closure. [TOOL:splunk] provides real-time monitoring and alerting. [TOOL:crowdstrike] provides automated incident tracking and case management. [ISSO] maintains incident log and provides monthly status reports to [ISSM]. Lessons learned incorporated into updated procedures.",tools:["splunk","crowdstrike"]},"IR-5(1)":{title:"Incident Monitoring | Automated Tracking and Collection",body:"[SYSTEM] employs automated mechanisms to assist in tracking incidents and collecting and analyzing incident information. [TOOL:crowdstrike] automated case management tracks incident lifecycle. [TOOL:splunk] automated correlation collects and analyzes incident-related log data. Automated mechanisms preserve evidence integrity during collection. Incident tracking data feeds into [ORG]'s monthly security reporting.",tools:["crowdstrike","splunk"]},"IR-6":{title:"Incident Reporting",body:"[ORG] requires immediate reporting of suspected incidents to [ISSO]. [ISSO] reports confirmed incidents to [ISSM] within 1 hour and appropriate CSSP within 4 hours. Cyber incidents reported to DoD via DIBNet within 72 hours per DFARS 252.204-7012. [TOOL:crowdstrike] automated alerting notifies security personnel in real time. [TOOL:splunk] triggers automated notifications for defined incident indicators.",tools:["crowdstrike","splunk"]},"IR-6(1)":{title:"Incident Reporting | Automated Reporting",body:"[SYSTEM] employs automated mechanisms to assist in reporting incidents. [TOOL:crowdstrike] automated alerting immediately notifies the [ISSO] and [ISSM] of high-severity detections. [TOOL:splunk] correlation rules generate automated incident tickets. Automated notifications include: incident severity, affected systems, initial indicators, and recommended response actions. Automated reporting is tested quarterly.",tools:["crowdstrike","splunk"]},"IR-6(3)":{title:"Incident Reporting | Supply Chain Coordination",body:"[ORG] provides incident information to the provider of the affected product or service and other organizations identified in the supply chain for incidents involving supply chain events. Supply chain incidents are reported per SR-8 notification agreements. [TOOL:crowdstrike] provides supply chain threat intelligence. The [ISSM] coordinates supply chain incident reporting with appropriate organizations.",tools:["crowdstrike"]},"IR-7":{title:"Incident Response Assistance",body:"[ORG] provides IR support for [SYSTEM] users. [ISSO] is primary contact for IR assistance. [ORG] maintains relationships with CSSP (DCSA ISOC, DIBNet, US-CERT) for external IR assistance. [TOOL:crowdstrike] provides 24/7 threat intelligence and IR support via OverWatch. Contact information for IR resources is documented in the IR plan.",tools:["crowdstrike"]},"IR-7(1)":{title:"IR Assistance | Automation Support for Availability of Information",body:"[SYSTEM] employs automated mechanisms to increase availability of incident response information and support. [TOOL:crowdstrike] provides automated threat intelligence and recommended response actions. [TOOL:splunk] dashboards provide real-time incident status visibility to authorized personnel. IR runbooks are maintained in [ORG]'s document management system accessible during incidents.",tools:["crowdstrike","splunk"]},"IR-8":{title:"Incident Response Plan",body:"[ORG] maintains a formal IRP consistent with NIST SP 800-61 and DoDI 8530.01 documenting: incident classification, roles/responsibilities, detection/analysis procedures, containment/eradication/recovery steps, and DFARS 252.204-7012 reporting timelines. Reviewed annually. Maintained in [TOOL:emass]. Tested annually via tabletop.",tools:["emass"]},"IR-9":{title:"Information Spillage Response",body:"[ORG] responds to information spills to [SYSTEM] or from [SYSTEM] by implementing specific containment and eradication procedures. The [ISSO] is responsible for coordinating information spillage response. [TOOL:crowdstrike] host isolation capability prevents spread from spilled information. [TOOL:splunk] supports identification of systems affected by information spills. Information spillage response procedures are documented in the IR plan and personnel trained annually.",tools:["crowdstrike","splunk"]},"IR-10":{title:"Integrated Information Security Analysis Team",body:"[ORG] establishes an integrated security analysis team for [SYSTEM] consisting of [ISSO], [ISSM], system admins, and network admins. Team coordinates using [TOOL:crowdstrike] and [TOOL:splunk]. Team meets monthly for security trend review and quarterly for formal threat analysis. [TOOL:crowdstrike] threat intelligence is incorporated into analysis activities.",tools:["crowdstrike","splunk"]}};export{e as default};
